SELECT grade_level, students
FROM enrollments
WHERE school_id = (SELECT school_id FROM schools WHERE school_name = 'Academy Of Applied Mathematics And Technology');

SELECT COUNT(*) AS total_schools
FROM school_locations
WHERE city = 'Bronx' AND state = 'NY';

SELECT school_name, school_id, pt_ratio 
FROM schools 
WHERE pt_ratio = (SELECT MAX(pt_ratio) FROM schools);

SELECT 
    (SELECT school_name FROM schools ORDER BY pt_ratio DESC LIMIT 1) AS school_with_highest_ratio,
    (SELECT school_name FROM schools ORDER BY pt_ratio ASC LIMIT 1) AS school_with_lowest_ratio;

SELECT
  (SELECT username FROM users WHERE user_id = 1 AND role = 'Analyst') AS Analyst_Username,
  (SELECT value FROM school_performance WHERE school_id = 1 AND metric = 'Graduation Rate') AS Graduation_Rate;
